def solve(param):
    count = {}
    for id_ in param['actual']:
        count[id_] = count.get(id_, 0) + 1
    missing = []
    for id_ in param['expected']:
        if count.get(id_, 0) > 0:
            count[id_] -= 1
        else:
            missing.append(id_)
    return missing
